@using SkiaSharp
@using SkiaSharp.Views.Blazor

<h1>SKGLView GRContext Access Test</h1>
<SKGLView @ref="skGLView" OnPaintSurface="OnPaintSurface" style="width:400px;height:300px;" />

@code {
    private SKGLView? skGLView;
    private void OnPaintSurface(SKPaintGLSurfaceEventArgs e)
    {
        var canvas = e.Surface.Canvas;
        canvas.Clear(SKColors.CornflowerBlue);
        // Issue #2329: Attempt to access GRContext from the view
        var grContext = skGLView?.GRContext;
        Console.WriteLine($"GRContext: {grContext}");
    }
}

